function main({qfd_json,sensitivity_json,gds_json}){
  var g=p(gds_json);
  var qfd=p(qfd_json);
  var sensRaw=p(sensitivity_json);
  var uReqs=qfd.user_requirements||[];
  var eParams=qfd.engineering_params||[];
  var relMatrix=qfd.relation_matrix||{};
  var sens=Array.isArray(sensRaw)?sensRaw:(sensRaw.parameters||[]);
  var sensMap={};
  sens.forEach(function(s){sensMap[s.ep_id||s.id]=parseFloat(s.sensitivity_score)||0;});
  var qfdScores={};
  eParams.forEach(function(ep){
    var score=0;
    uReqs.forEach(function(ur){score+=(ur.importance||5)*((relMatrix[ur.id]||{})[ep.id]||0);});
    qfdScores[ep.id]=score;
  });
  var maxQfd=Math.max.apply(null,Object.values(qfdScores).concat([1]));
  var engineeringParams=eParams.map(function(ep){
    var qw=qfdScores[ep.id]/maxQfd;
    var sw=sensMap[ep.id]||0;
