    return {参数ID:ep.id,名称:ep.name||ep.id,目标值:ep.baseline||'',单位:ep.unit||'mm',范围下限:ep.min||'',范围上限:ep.max||'',优化方向:ep.direction||'↑',QFD权重:Math.round(qfdScores[ep.id]||0),灵敏度系数:sw,综合权重:cw,优先级:cw>0.66?'high':cw>0.33?'medium':'low',约束类型:'软约束'};
