var RELATION_TYPES=['attached_to','supports','contains','aligned_with','mounted_on','rests_on','clearance_to','patterned_from','mirrors'];
var POSE_TYPES=['part_frame_attach','hinge_with_params','mounted_alignment','containment','clearance_offset','patterned_from','mirrored','aligned_with','generic'];
var SHAPE_FAMILIES=['box','cylinder','cone','sphere','torus','revolved_profile','swept_profile','lofted','composite','freeform'];
var ID_RE=/^[A-Za-z0-9_.:-]+$/;
function main({cleaned_json,gds_json}){
  var g=p(gds_json)||{};
  if(!g._meta)g._meta={迭代计数:{fbs:0,schema:0},schema_errors:[]};
  if(!g._meta.迭代计数)g._meta.迭代计数={fbs:0,schema:0};
  var iter=g._meta.迭代计数.schema||0;
  g._meta.迭代计数.schema=iter+1;
  var f=p(cleaned_json);
  if(!f){g._meta.schema_errors=['无法解析生成的JSON'];var r=iter>=2?'pass':'fail';return {validation_result:r,error_list:JSON.stringify(g._meta.schema_errors),updated_gds_json:JSON.stringify(g),fragments_for_merge:cleaned_json||'{}'};}
  var errors=[];
  var od=f.objectDefinition||f.对象定义;
  var gr=f.geometryRequirements||f.几何要求;
  var ms=f.materialAndSurface||f.材料与表面;
  if(!od)errors.push('缺少 objectDefinition');
  if(!gr)errors.push('缺少 geometryRequirements');
  if(!ms)errors.push('缺少 materialAndSurface');
  var partIds={};
  if(od){
    var rootObj=od.rootObject||od.根对象;
    if(!rootObj||(!(rootObj.objectId||rootObj.对象标识)))errors.push('rootObject 缺少 objectId');
    var parts=od.parts||od.部件列表||[];
    parts.forEach(function(pt){
      var pid=pt.partId||pt.部件标识;
      if(!pid){errors.push('part 缺少 partId');return;}
      if(!ID_RE.test(pid))errors.push('partId "'+pid+'" 含非法字符');
      partIds[pid]=true;
    });
    var rels=od.relations||od.关系列表||[];
    rels.forEach(function(rel){
      var rt=rel.relationType||rel.类型;
      if(rt&&RELATION_TYPES.indexOf(rt)<0)errors.push('relationType "'+rt+'" 不在枚举列表');
      var pose=rel.pose||rel.姿态||{};
      var pt=pose.poseType||pose.姿态类型;
      if(pt&&POSE_TYPES.indexOf(pt)<0)errors.push('poseType "'+pt+'" 不在枚举列表');
      var fp=rel.fromPart||rel.起始部件;var tp=rel.toPart||rel.目标部件;
      if(fp&&!partIds[fp])errors.push('fromPart "'+fp+'" 未在parts中定义');
      if(tp&&!partIds[tp])errors.push('toPart "'+tp+'" 未在parts中定义');
    });
  }
  var paramIds={};
  if(gr){
    var paramSet=gr.parameterSet||gr.参数集||[];
    paramSet.forEach(function(pm){
      var pmid=pm.parameterId||pm.参数标识;
      if(!pmid){errors.push('parameter 缺少 parameterId');return;}
      if(!ID_RE.test(pmid))errors.push('parameterId "'+pmid+'" 含非法字符');
      paramIds[pmid]=true;
    });
    if(od){
      var parts=od.parts||od.部件列表||[];
      parts.forEach(function(pt){
        var gRef=pt.geometryRef||pt.几何引用||[];
        gRef.forEach(function(ref){if(!paramIds[ref])errors.push('part "'+(pt.partId||pt.部件标识)+'" geometryRef "'+ref+'" 未在parameterSet中定义');});
      });
    }
  }
  if(ms&&od){
    var matCat=ms.materialCatalog||ms.材料目录||[];
    var matIds={};
    matCat.forEach(function(m){var mid=m.materialId||m.材料标识;if(mid)matIds[mid]=true;});
    var parts=od.parts||od.部件列表||[];
    parts.forEach(function(pt){
      var mRef=pt.materialRef||pt.材料引用;
      if(mRef&&!matIds[mRef])errors.push('part "'+(pt.partId||pt.部件标识)+'" materialRef "'+mRef+'" 未在materialCatalog中定义');
    });
  }
  g._meta.schema_errors=errors;
  var result=(errors.length===0||iter>=2)?'pass':'fail';
  return {validation_result:result,error_list:JSON.stringify(errors),updated_gds_json:JSON.stringify(g),fragments_for_merge:cleaned_json};
}

